const settings = $('Load Global Settings').first()?.json ?? {};
const request = $('Send Treasury Refund Request Webhook').first()?.json ?? $input.first()?.json ?? {};
const body = request.body ?? {};
const headers = request.headers ?? {};
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const truthy = (value) => ['1', 'true', 'yes', 'y', 'on'].includes(clean(value).toLowerCase());
const deriveBaseUrl = (headers, fallback) => {
  const forwardedProto = clean(headers['x-forwarded-proto']);
  const forwardedHost = clean(headers['x-forwarded-host']);
  const host = forwardedHost || clean(headers.host);
  const forwardedPort = clean(headers['x-forwarded-port']);
  if (!host) return fallback;
  const proto = forwardedProto || 'http';
  let authority = host;
  if (forwardedPort && !authority.includes(':')) {
    const isDefaultPort = (proto === 'http' && forwardedPort === '80') || (proto === 'https' && forwardedPort === '443');
    if (!isDefaultPort) authority = `${authority}:${forwardedPort}`;
  }
  return `${proto}://${authority}`;
};
const refundId = parseInt(clean(body.refund_id), 10);
const returnUrl = clean(body.return_url) || `${deriveBaseUrl(headers, 'http://n8n:5678')}/webhook/refund-status-form?id=${refundId}`;
const testMode = truthy(body.test_mode);
const refund = $('Load Refund Details').first()?.json ?? {};
const template = $('Load Treasury Template').first()?.json ?? {};
const validStatuses = ['Ready For Treasury', 'Sent To Treasury'];
const errorMessage = !refundId || isNaN(refundId) ? 'refund_id is required'
  : !refund.id ? 'Refund not found'
  : !validStatuses.includes(refund.status) ? `Refund must be in status '${validStatuses.join("' or '")}' to send to treasury`
  : !template.template_key ? 'Treasury email template not found'
  : '';
return [{ json: {
  refund_id: refundId,
  name: refund.name ?? '',
  refund_for: refund.refund_for ?? '',
  membership: refund.membership ?? '',
  amount: refund.amount ?? 0,
  refund: refund.refund ?? 0,
  from_date: refund.from_date ?? '',
  to_date: refund.to_date ?? '',
  reason: refund.reason ?? '',
  explanation: refund.explanation ?? '',
  status: refund.status ?? '',
  current_status: refund.status ?? '',
  treasury_email: clean(body.treasury_email) || 'treasury.avondaleltc@gmail.com',
  intended_recipient: clean(body.treasury_email) || 'treasury.avondaleltc@gmail.com',
  actual_recipient: testMode ? (clean(settings.default_test_recipient) || 'steve.short@gmail.com') : (clean(body.treasury_email) || 'treasury.avondaleltc@gmail.com'),
  delivery_mode: testMode ? 'test' : 'production',
  template_key: template.template_key || 'refund_request_treasury',
  template_name: template.template_name || 'Refund Request Treasury',
  subject_template: template.subject_template || 'Refund request: {{refund_for}} ({{membership}})',
  text_template: template.text_template || '',
  html_template: template.html_template || '',
  sender_name: clean(settings.email_sender_name) || 'Steve Short',
  reply_to: clean(settings.email_reply_to) || 'members.avondaleltc@gmail.com',
  return_url: returnUrl,
  error_message: errorMessage
} }];

const input = $('Resolve Send Request').first().json ?? {};
const message = input.error_message || 'Unable to send treasury refund request.';
const returnUrl = input.return_url || '#';
const escapeHtml = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&#39;');
const html = `<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Treasury Request Not Sent</title><style>body{margin:0;padding:24px;background:#f7f8fc;font-family:Lato,'Helvetica Neue',Arial,sans-serif;color:#2e3d4e}.panel{max-width:760px;margin:0 auto;background:#fff;border:1px solid #e2e8f0;border-radius:18px;box-shadow:0 18px 40px rgba(53,72,91,.08);padding:28px}h1{margin:0 0 10px;font-size:30px}p{color:#6b7785;line-height:1.5}.message{margin:18px 0;padding:14px 16px;border-radius:14px;background:#fdecec;color:#b93a3a;font-weight:700}.actions{margin-top:22px;display:flex;gap:12px;flex-wrap:wrap}.button{display:inline-flex;align-items:center;justify-content:center;padding:12px 18px;border-radius:999px;text-decoration:none;font-weight:700;background:linear-gradient(135deg,#509ee3 0%,#2f80d8 100%);color:#fff}</style></head><body><div class="panel"><h1>Treasury Refund Request Not Sent</h1><p>The treasury refund request could not be sent.</p><div class="message">${escapeHtml(message)}</div><div class="actions"><a class="button" href="${escapeHtml(returnUrl)}">Back to Status Form</a></div></div></body></html>`;
return [{ json: { html } }];

const input = $('Resolve Send Request').first().json ?? {};
const formatDate = (value) => {
  if (!value) return '';
  const d = new Date(value);
  return `${d.getDate()}/${d.getMonth() + 1}/${d.getFullYear()}`;
};
const formatMoney = (value) => {
  const rounded = Math.round((Number(value) + Number.EPSILON) * 100) / 100;
  return `£${Number.isInteger(rounded) ? rounded : rounded.toFixed(2)}`;
};
const applyTokens = (value) => {
  if (!value) return '';
  return value
    .replace(/\{\{name\}\}/g, input.name ?? '')
    .replace(/\{\{refund_for\}\}/g, input.refund_for ?? '')
    .replace(/\{\{reason\}\}/g, input.reason ?? '')
    .replace(/\{\{membership\}\}/g, input.membership ?? '')
    .replace(/\{\{amount\}\}/g, formatMoney(input.amount))
    .replace(/\{\{refund\}\}/g, formatMoney(input.refund))
    .replace(/\{\{from_date\}\}/g, formatDate(input.from_date))
    .replace(/\{\{to_date\}\}/g, formatDate(input.to_date))
    .replace(/\{\{explanation\}\}/g, input.explanation ?? '');
};
const subject = applyTokens(input.subject_template);
const message = applyTokens(input.text_template);
return [{ json: {
  sender_name: input.sender_name,
  reply_to: input.reply_to,
  recipient: input.actual_recipient,
  subject,
  message,
  refund_id: input.refund_id,
  refund_for: input.refund_for,
  intended_recipient: input.intended_recipient,
  delivery_mode: input.delivery_mode,
  return_url: input.return_url
} }];

const input = $('Render Email Content').first().json ?? {};
const result = $('Send Gmail Message').first()?.json ?? {};
const messageId = result.id || result.message?.id || '';
return [{ json: { ...input, message_id: messageId } }];

const input = $('Capture Message ID').first().json ?? {};
const sqlLiteral = (value) => {
  if (value === null || value === undefined || value === '') return 'NULL';
  return "'" + String(value).replace(/'/g, "''") + "'";
};
const sql = `UPDATE public.refunds
SET status = 'Sent To Treasury',
    treasury_email_message_id = ${sqlLiteral(input.message_id)},
    updated_at = now()
WHERE id = ${input.refund_id}
RETURNING id, status, refund_for;`;
return [{ json: { sql } }];

const input = $('Capture Message ID').first().json ?? {};
const updated = $('Update Refund Status').first()?.json ?? {};
const escapeHtml = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&#39;');
const modeLabel = input.delivery_mode === 'production' ? 'Production' : 'Test';
const recipientSummary = input.delivery_mode === 'production' ? escapeHtml(input.intended_recipient) : `${escapeHtml(input.actual_recipient)} (intended: ${escapeHtml(input.intended_recipient)})`;
const html = `<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Treasury Request Sent</title><style>body{margin:0;padding:24px;background:#f7f8fc;font-family:Lato,'Helvetica Neue',Arial,sans-serif;color:#2e3d4e}.panel{max-width:760px;margin:0 auto;background:#fff;border:1px solid #e2e8f0;border-radius:18px;box-shadow:0 18px 40px rgba(53,72,91,.08);padding:28px}h1{margin:0 0 10px;font-size:30px}p{color:#6b7785;line-height:1.5}.pill{display:inline-flex;align-items:center;padding:8px 12px;border-radius:999px;background:#edf8f2;color:#1f7a4d;font-weight:700;margin:12px 0 18px}dl{display:grid;grid-template-columns:max-content 1fr;gap:10px 16px;margin:0}dt{font-weight:700}dd{margin:0;color:#2e3d4e}.actions{margin-top:22px;display:flex;gap:12px;flex-wrap:wrap}.button{display:inline-flex;align-items:center;justify-content:center;padding:12px 18px;border-radius:999px;text-decoration:none;font-weight:700;background:linear-gradient(135deg,#509ee3 0%,#2f80d8 100%);color:#fff}</style></head><body><div class="panel"><h1>Treasury Refund Request Sent</h1><p>The refund request has been sent to treasury.</p><div class="pill">${escapeHtml(modeLabel)} mode</div><dl><dt>Refund ID</dt><dd>${input.refund_id}</dd><dt>Refund For</dt><dd>${escapeHtml(input.refund_for)}</dd><dt>Recipient</dt><dd>${recipientSummary}</dd><dt>New Status</dt><dd>${escapeHtml(updated.status || 'Sent To Treasury')}</dd><dt>Message ID</dt><dd>${escapeHtml(input.message_id)}</dd></dl><div class="actions"><a class="button" href="${escapeHtml(input.return_url)}">Back to Status Form</a></div></div></body></html>`;
return [{ json: { html } }];
